async function getImageUrls(dbKey, deviceName, category) {
  var key = (dbKey || deviceName).toLowerCase();
  var imgs = LOCAL_IMGS[key];
  if (imgs && imgs.length) return imgs;
  return await searchWikimediaCommons(deviceName);
}